{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "mspTenantId":   { "type": "string", "defaultValue": "<MSP_TENANT_ID>" },
    "mspOfferName":  { "type": "string", "defaultValue": "Contoso MSP Managed Services" },
    "mspOfferDesc":  { "type": "string", "defaultValue": "Contoso MSP full managed service offer v2" }
  },
  "variables": {
    "roleContributor":        "b24988ac-6180-42a0-ab88-20f7382dd24c",
    "roleReader":             "acdd72a7-3385-48ef-bd42-f606fba81ae7",
    "rolePolicyContributor":  "36243c78-bf99-498c-9df9-86d9f8d28608",
    "roleMonitoringReader":   "43d0d8ad-25c7-4714-9337-8ba259a9fe05"
  },
  "resources": [
    {
      "type": "Microsoft.ManagedServices/registrationDefinitions",
      "apiVersion": "2022-10-01",
      "name": "[guid(subscription().id, parameters('mspOfferName'))]",
      "properties": {
        "registrationDefinitionName": "[parameters('mspOfferName')]",
        "description": "[parameters('mspOfferDesc')]",
        "managedByTenantId": "[parameters('mspTenantId')]",
        "authorizations": [
          {
            "principalId": "<MSP_TIER1_GROUP_OID>",
            "principalIdDisplayName": "MSP Tier-1 Support",
            "roleDefinitionId": "[variables('roleReader')]"
          },
          {
            "principalId": "<MSP_ENGINEERS_GROUP_OID>",
            "principalIdDisplayName": "MSP Engineers",
            "roleDefinitionId": "[variables('roleContributor')]"
          },
          {
            "principalId": "<MSP_POLICY_SP_OID>",
            "principalIdDisplayName": "MSP Policy Automation",
            "roleDefinitionId": "[variables('rolePolicyContributor')]"
          },
          {
            "principalId": "<MSP_MONITORING_GROUP_OID>",
            "principalIdDisplayName": "MSP Monitoring Team",
            "roleDefinitionId": "[variables('roleMonitoringReader')]"
          }
        ]
      }
    },
    {
      "type": "Microsoft.ManagedServices/registrationAssignments",
      "apiVersion": "2022-10-01",
      "name": "[guid(subscription().id, parameters('mspOfferName'), 'assign')]",
      "dependsOn": [
        "[resourceId('Microsoft.ManagedServices/registrationDefinitions',
          guid(subscription().id, parameters('mspOfferName')))]"
      ],
      "properties": {
        "registrationDefinitionId": "[resourceId('Microsoft.ManagedServices/registrationDefinitions',
          guid(subscription().id, parameters('mspOfferName')))]"
      }
    }
  ]
}

{
  "authorizations": [
    {
      "principalId": "<MSP_ENGINEERS_GROUP_OID>",
      "principalIdDisplayName": "MSP Engineers (permanent read)",
      "roleDefinitionId": "acdd72a7-3385-48ef-bd42-f606fba81ae7"
    }
  ],
  "eligibleAuthorizations": [
    {
      "justInTimeAccessPolicy": {
        "multiFactorAuthProvider": "Azure",
        "maximumActivationDuration": "PT8H",
        "managedByTenantApprovers": [
          {
            "principalId": "<MSP_APPROVER_GROUP_OID>",
            "principalIdDisplayName": "MSP Change Advisory Board"
          }
        ]
      },
      "principalId": "<MSP_ENGINEERS_GROUP_OID>",
      "principalIdDisplayName": "MSP Engineers (JIT contributor)",
      "roleDefinitionId": "b24988ac-6180-42a0-ab88-20f7382dd24c"
    },
    {
      "justInTimeAccessPolicy": {
        "multiFactorAuthProvider": "Azure",
        "maximumActivationDuration": "PT2H",
        "managedByTenantApprovers": []
      },
      "principalId": "<MSP_INCIDENT_RESPONDER_OID>",
      "principalIdDisplayName": "MSP Incident Responders (JIT Owner, self-approve)",
      "roleDefinitionId": "8e3af657-a8ff-443c-a75c-2fe8c4bcb635"
    }
  ]
}
